const STORAGE_KEY="reptrak-user",defaultUser={name:"",habit:"",frequency:"",count:0,streak:0,minutes:0,weekly:[!1,!1,!1,!1,!1,!1,!1]};function loadUser(){try{const e=localStorage.getItem(STORAGE_KEY);return e?{...defaultUser,...JSON.parse(e)}:{...defaultUser}}catch{return{...defaultUser}}}let user=loadUser();function saveUser(){localStorage.setItem(STORAGE_KEY,JSON.stringify(user))}window.user=user,window.saveUser=saveUser;